import type { NordicDeviceType } from '../../common/types';

import { getReq } from '@meli/server-context';

const KNOWN_TYPES = new Set<NordicDeviceType>([
  'desktop',
  'mobile',
  'tablet',
]) as Set<string>;

export function getDeviceType(): NordicDeviceType {
  const { type } = getReq().device;

  if (KNOWN_TYPES.has(type)) {
    return type as NordicDeviceType;
  }

  return 'desktop';
}
